const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
return { json: { _ok: true } };

const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const events  = allOf('Fetch Events 24h');
const creds   = allOf('Fetch Credentials');
const alerts  = allOf('Fetch Security Alerts');
const rules   = allOf('Fetch Rules');
const now = Date.now();

// Event type buckets + severity counts (last 24h).
const byType = {};
const sevCounts = { info: 0, warning: 0, critical: 0 };
events.forEach(function (e) {
  byType[e.event_type] = (byType[e.event_type] || 0) + 1;
  if (sevCounts[e.severity] !== undefined) sevCounts[e.severity] += 1;
});

// Top offenders: IP + email by failed-auth-type events.
const failedTypes = ['login_failed','session_rejected','webhook_auth_failed','privilege_denied'];
const byIp = {};
const byEmail = {};
events.forEach(function (e) {
  if (failedTypes.indexOf(e.event_type) === -1) return;
  if (e.source_ip) byIp[e.source_ip]    = (byIp[e.source_ip]    || 0) + 1;
  if (e.user_email) byEmail[e.user_email] = (byEmail[e.user_email] || 0) + 1;
});
function topN(obj, n) {
  return Object.keys(obj).map(function (k) { return { key: k, count: obj[k] }; })
    .sort(function (a, b) { return b.count - a.count; }).slice(0, n);
}

// Enrich credentials with days_to_due + rotation_status.
const enrichedCreds = creds.map(function (c) {
  const dueAt = c.next_rotation_due ? new Date(c.next_rotation_due).getTime() : null;
  const daysToDue = dueAt ? Math.floor((dueAt - now) / 86400000) : null;
  let rotation_status = 'ok';
  if (daysToDue !== null) {
    if (daysToDue < 0) rotation_status = 'overdue';
    else if (daysToDue <= (c.warning_threshold_days || 14)) rotation_status = 'due_soon';
  }
  return Object.assign({}, c, { days_to_due: daysToDue, rotation_status: rotation_status });
});
const credCounts = { ok: 0, due_soon: 0, overdue: 0 };
enrichedCreds.forEach(function (c) { credCounts[c.rotation_status] = (credCounts[c.rotation_status] || 0) + 1; });

// Security posture score (0-100). Penalties for unresolved findings.
let score = 100;
score -= credCounts.overdue * 10;
score -= credCounts.due_soon * 3;
score -= sevCounts.critical * 8;
score -= sevCounts.warning * 2;
score -= alerts.filter(function (a) { return a.status === 'open' && a.severity === 'critical'; }).length * 10;
score -= alerts.filter(function (a) { return a.status === 'open' && a.severity === 'warning'; }).length * 3;
score = Math.max(0, Math.min(100, score));

return { json: {
  ok: true,
  generated_at: new Date().toISOString(),
  posture_score: score,
  events_last_24h: events.length,
  event_type_counts: byType,
  severity_counts: sevCounts,
  top_offending_ips: topN(byIp, 5),
  top_offending_emails: topN(byEmail, 5),
  credentials: enrichedCreds,
  credential_counts: credCounts,
  rules: rules,
  alerts: alerts
} };
